function deriveDictionaries(s){return{
 operationTypes:[...new Set((s.operations||[]).map(x=>x.type).filter(Boolean))],
 categories:[...new Set((s.categories||[]).map(x=>x.name).filter(Boolean))],
 accounts:[...new Set((s.operations||[]).map(x=>x.account).filter(Boolean))],
 groups:[...new Set((s.categories||[]).map(x=>x.group).concat((s.operations||[]).map(x=>x.group)).filter(Boolean))],
 plannedValues:[...new Set((s.operations||[]).map(x=>x.plannedFlag).filter(Boolean))],
 planStatuses:['Запланировано','Выполнено','Отменено','Перенесено'],priorities:['Обязательно','Желательно','Можно отложить'],planTypes:[],subcategories:{}
}}
function migrate(input){
 const base=seedDefaults||defaults,s=input&&typeof input==='object'?input:clone(base);
 s.version=Number(s.version)||SCHEMA_VERSION;
 s.settings={...base.settings,...(s.settings||{})};
 s.operations=Array.isArray(s.operations)?s.operations:clone(base.operations||[]);
 s.operations.forEach(o=>{delete o.tags});
 s.incomes=s.operations.filter(o=>operationKindFromState(s,o)==='income');
 s.expenses=s.operations.filter(o=>['expense','credit'].includes(operationKindFromState(s,o)));
 s.plans=Array.isArray(s.plans)?s.plans:clone(base.plans||[]);
 s.categories=Array.isArray(s.categories)?s.categories:clone(base.categories||[]);
 s.limits=Object.fromEntries(s.categories.filter(c=>['fixed','limit','plan'].includes(c.controlType)).map(c=>[c.name,c.amount]));
 if(!Array.isArray(s.goals))s.goals=clone(base.goals||[]);s.goals.forEach(g=>{if(g.type==='buffer')g.type='Подушка'});
 if(!Array.isArray(s.obligations))s.obligations=clone(base.obligations||[]);
 s.creditCard={...(base.creditCard||defaults.creditCard),...(s.creditCard||{})};
 s.dictionaries={...deriveDictionaries(s),...(base.dictionaries||{}),...(s.dictionaries||{})};
 s.dictionaries.categories=s.categories.map(x=>x.name);
 if(!Array.isArray(s.notifications))s.notifications=[];
 s.settings.notificationPrefs=s.settings.notificationPrefs||{disabled:[],snoozed:{}};
 s.updatedAt=s.updatedAt||new Date().toISOString();
 if(s.version<SCHEMA_VERSION)s.version=SCHEMA_VERSION;
 return s;
}
function operationKindFromState(s,o){const types=s.dictionaries?.operationTypes||deriveDictionaries(s).operationTypes||[],creditName=(s.categories||[]).find(c=>c.controlType==='plan')?.name,goalNames=(s.categories||[]).filter(c=>c.controlType==='goal').map(c=>c.name);if(o.type==='Вывод из накоплений')return'withdrawal';if(o.type==='Доход'||o.type===types[0])return'income';if(o.type==='Кредитка'||o.type===types[2]||o.category===creditName)return'credit';if(o.type==='Накопления'||o.type===types[3]||goalNames.includes(o.category))return'savings';return'expense'}
function readStoredState(){const keys=[KEY,...LEGACY_STORAGE_KEYS];for(const key of keys){try{const raw=localStorage.getItem(key);if(raw)return{key,data:JSON.parse(raw)}}catch(e){console.warn('Storage read failed for '+key,e)}}return null}
function load(){const stored=readStoredState();if(!stored){const fresh=migrate(clone(seedDefaults));try{localStorage.setItem(KEY,JSON.stringify(fresh))}catch(e){console.warn('Initial local save failed',e)}return fresh}const migrated=migrate(stored.data);try{localStorage.setItem(KEY,JSON.stringify(migrated))}catch(e){console.warn('Migration local save failed',e)}return migrated}
function save(){try{state=migrate(state);state.updatedAt=new Date().toISOString();localStorage.setItem(KEY,JSON.stringify(state));setLocalSaveStatus('saved')}catch(e){console.error('Local save failed',e);setLocalSaveStatus('error')}}
function setLocalSaveStatus(status){const labels={saving:'сохраняем…',saved:'локально сохранено',error:'ошибка сохранения'},node=document.querySelector('#localSaveStatus');if(node){node.textContent=labels[status]||status;node.className='cloud-sync-status '+(status==='error'?'error':'saved')}clearTimeout(saveStatusTimer);if(status==='saved')saveStatusTimer=setTimeout(()=>{const n=document.querySelector('#localSaveStatus');if(n)n.textContent='локальная копия'},1800)}
const el=s=>document.querySelector(s);
const sum=(a,fn)=>a.reduce((x,v)=>x+(Number(fn(v))||0),0);
const money=n=>new Intl.NumberFormat('ru-RU',{maximumFractionDigits:0}).format(Math.round(Number(n)||0))+' ₽';
const niceDate=d=>new Date(d+'T00:00').toLocaleDateString('ru-RU',{day:'numeric',month:'short',year:'numeric'});
const todayISO=()=>new Date().toISOString().slice(0,10);
const escapeHtml=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const optionList=(a,current)=>a.map(x=>`<option ${x===current?'selected':''}>${escapeHtml(x)}</option>`).join('');
function operationKind(o){const types=state.dictionaries?.operationTypes||[],creditName=state.categories.find(c=>c.controlType==='plan')?.name,goalNames=state.categories.filter(c=>c.controlType==='goal').map(c=>c.name);if(o.type==='Вывод из накоплений')return'withdrawal';if(o.type==='Доход'||o.type===types[0])return'income';if(o.type==='Кредитка'||o.type===types[2]||o.category===creditName)return'credit';if(o.type==='Накопления'||o.type===types[3]||goalNames.includes(o.category))return'savings';return'expense'}
function planKind(p){return operationKind(p)}
function requestedKind(type){return({Доход:'income',Расход:'expense',Накопления:'savings','Вывод из накоплений':'withdrawal',Кредитка:'credit'})[type]||type}
function facts(type){const kind=requestedKind(type);return sum(state.operations.filter(o=>!type||operationKind(o)===kind),o=>o.amount)}
function activePlans(type){const kind=requestedKind(type);return sum(state.plans.filter(p=>!['Отменено','Выполнено'].includes(p.status)&&(!type||planKind(p)===kind)),p=>p.amount)}
function isPaid(x){return['Оплачено','paid'].includes(x.status)}
function setPaid(x,value){x.status=value?'paid':'unpaid'}
function totals(){
 const inc=facts('Доход'),exp=facts('Расход'),saved=facts('Накопления'),withdrawn=facts('Вывод из накоплений'),credit=facts('Кредитка');
 const balance=inc+withdrawn-exp-saved-credit;
 const reserves=sum(state.obligations.filter(x=>!isPaid(x)),x=>x.amount)+activePlans('Расход')+activePlans('Накопления')+Math.max(0,(state.creditCard.plannedPayment||state.creditCard.minPayment)-state.creditCard.paidThisMonth);
 return{inc,exp,saved,withdrawn,credit,balance,reserves,free:balance-reserves,forecast:balance+activePlans('Доход')-activePlans('Расход')-activePlans('Накопления')-activePlans('Кредитка')};
}
function daysUntil(day){const now=new Date(),target=new Date(now.getFullYear(),now.getMonth(),day);if(target<now)target.setMonth(target.getMonth()+1);return Math.max(0,Math.ceil((target-now)/86400000))}
function categoryFact(name){return sum(state.operations.filter(o=>o.category===name&&!['income','withdrawal'].includes(operationKind(o))),o=>o.amount)}
function categoryPlan(name){return sum(state.plans.filter(p=>p.category===name&&p.status==='Запланировано'),p=>p.amount)}
function overages(){return state.categories.filter(c=>c.controlType==='limit'&&categoryFact(c.name)+categoryPlan(c.name)>c.amount)}
function categoryExpenses(){return state.categories.map(c=>({...c,fact:categoryFact(c.name)})).filter(c=>c.fact>0&&c.controlType!=='goal').sort((a,b)=>b.fact-a.fact)}
function categoryOperations(name,limit=5){return [...state.operations].filter(o=>o.category===name&&['expense','credit'].includes(operationKind(o))).sort((a,b)=>b.date.localeCompare(a.date)).slice(0,limit)}
function addMonths(date,count){const d=new Date(date);d.setMonth(d.getMonth()+count);return d}
function monthLabel(date){return date.toLocaleDateString('ru-RU',{month:'short',year:'2-digit'})}

function renderNav(){
 for(const id of ['#mobileNav','#desktopNav'])el(id).innerHTML=nav.map(([k,icon,label])=>`<button class="nav-item ${k===active?'active':''}" data-nav="${k}"><b>${icon}</b><span>${label}</span></button>`).join('');
 document.querySelectorAll('[data-nav]').forEach(b=>b.onclick=()=>{active=b.dataset.nav;render()});
}
function render(){renderNav();({home:homeScreen,entry:entryScreen,plan:planScreen,analytics:analyticsScreen,goals:goalsScreen,settings:settingsScreen}[active])();window.scrollTo({top:0,behavior:'smooth'})}
function title(h,p,action=''){return `<div class="section-head"><div><h1>${h}</h1>${p?`<p style="text-align:left;max-width:none;margin-top:5px">${p}</p>`:''}</div>${action}</div>`}
function progress(value,max){const pct=max?Math.min(100,Math.max(0,value/max*100)):0;return `<div class="progress"><i style="width:${pct}%"></i></div>`}

function homeScreen(){
 const t=totals(),unpaid=state.obligations.filter(x=>!isPaid(x)),overs=overages(),mainGoal=state.goals[0],withdrawals=state.operations.filter(o=>operationKind(o)==='withdrawal');
 el('#screen').innerHTML=`<div class="stack">
  <section class="hero home-widget" data-home-detail="balance"><div class="eyebrow">Доступно сейчас</div><div class="hero-value">${money(t.balance)}</div><div class="hero-line"></div><div class="hero-caption">На счетах до резервирования обязательств</div></section>
  <div class="summary-grid">
   <section class="card summary-card dark home-widget" data-home-detail="free"><span class="eyebrow">Свободно после резервов</span><strong class="value">${money(t.free)}</strong><span class="hint">Резервы: ${money(t.reserves)}</span></section>
   <section class="card summary-card ${unpaid.length?'warn':''} home-widget" data-home-detail="obligations"><span class="eyebrow">Не оплачено</span><strong class="value">${unpaid.length}</strong><span class="hint">На ${money(sum(unpaid,x=>x.amount))}</span></section>
   <section class="card summary-card ${overs.length?'warn':''} home-widget" data-home-detail="limits"><span class="eyebrow">Лимиты требуют разбора</span><strong class="value">${overs.length}</strong><span class="hint">Проблемных категорий</span></section>
   <section class="card summary-card home-widget" data-home-detail="forecast"><span class="eyebrow">Прогноз месяца</span><strong class="value">${money(t.forecast)}</strong><span class="hint">После активных планов</span></section>
  </div>
  <section class="card paydays home-widget" data-home-detail="paydays"><div class="payday"><div class="calendar-icon">▣</div><div><small>до аванса</small><strong>${daysUntil(state.settings.paydaySecond)}</strong> <em>дней</em><span>${state.settings.paydaySecond} число</span></div></div><div class="payday"><div class="calendar-icon">▣</div><div><small>до зарплаты</small><strong>${daysUntil(state.settings.paydayMain)}</strong> <em>дней</em><span>${state.settings.paydayMain} число</span></div></div><div class="forecast"><div><small class="eyebrow">Резервы месяца</small><div class="forecast-value">${money(t.reserves)}</div><p class="muted">Обязательства, планы и минимальный платёж</p></div><div class="insight">${t.free>=0?'После резервов бюджет остаётся положительным.':'Резервы выше доступного остатка — пересмотрите планы.'}</div></div></section>
  <div class="wide-grid">
   <section class="card home-widget" data-home-detail="obligations"><div class="card-title">Обязательные платежи</div><div class="action-list">${unpaid.length?unpaid.map(x=>`<div class="action-row"><div><strong>${escapeHtml(x.title)}</strong><p>До ${x.dueDay} числа · ${money(x.amount)}</p></div><button class="tiny-button" data-pay-obligation="${x.id}">Отметить оплаченным</button></div>`).join(''):'<div class="empty-compact">Все обязательные платежи оплачены</div>'}</div></section>
   <section class="card home-widget" data-home-detail="goals"><div class="card-title">Накопления</div><div class="goal-balance">${money(mainGoal?.saved||0)}</div>${progress(mainGoal?.saved||0,mainGoal?.target||1)}<p class="muted">${escapeHtml(mainGoal?.name||'Цель')} · ${Math.round((mainGoal?.saved||0)/(mainGoal?.target||1)*100)}%</p>${withdrawals.length?`<div class="insight">Выводы из накоплений за период: ${money(sum(withdrawals,x=>x.amount))}</div>`:'<div class="insight">Выводов из накоплений не было.</div>'}</section>
  </div>
  <section class="card home-widget" data-home-detail="actions"><div class="card-title">Что сделать сейчас</div>${assistantActions().map(x=>`<div class="insight" style="margin-top:8px">${x}</div>`).join('')}</section>
 </div>`;
 document.querySelectorAll('[data-pay-obligation]').forEach(b=>b.onclick=e=>{e.stopPropagation();const x=state.obligations.find(v=>v.id===b.dataset.payObligation);if(x){setPaid(x,true);save();homeScreen();toast('Платёж отмечен')}});
 document.querySelectorAll('[data-home-detail]').forEach(x=>x.onclick=e=>{if(e.target.closest('button'))return;openHomeDetail(x.dataset.homeDetail)});
}
function openHomeDetail(kind){const t=totals(),unpaid=state.obligations.filter(x=>!isPaid(x)),overs=overages(),details={balance:['Доступно сейчас',`<div class="detail-total">${money(t.balance)}</div><p class="report">Доходы минус расходы, накопления и платежи по кредитке. Резервы ещё не вычтены.</p>`],free:['Свободно после резервов',`<div class="detail-total">${money(t.free)}</div><div class="detail-grid"><span>Баланс<strong>${money(t.balance)}</strong></span><span>Резервы<strong>−${money(t.reserves)}</strong></span></div>`],forecast:['Прогноз месяца',`<div class="detail-total">${money(t.forecast)}</div><div class="detail-grid"><span>Текущий баланс<strong>${money(t.balance)}</strong></span><span>Изменение по планам<strong>${money(t.forecast-t.balance)}</strong></span></div>`],paydays:['Ближайшие доходы',`<div class="detail-grid"><span>Аванс через ${daysUntil(state.settings.paydaySecond)} дн.<strong>${money(state.settings.incomeSecond)}</strong></span><span>Зарплата через ${daysUntil(state.settings.paydayMain)} дн.<strong>${money(state.settings.incomeMain)}</strong></span></div>`],obligations:['Обязательные платежи',unpaid.length?`<div class="action-list">${unpaid.map(obligationRow).join('')}</div><button class="button secondary modal-route" data-route="plan">Открыть план</button>`:'<div class="empty-compact">Все обязательные платежи оплачены</div>'],limits:['Проблемные категории',overs.length?`<div class="action-list">${overs.map(c=>`<button class="detail-row" data-category-detail="${escapeHtml(c.name)}"><span>${escapeHtml(c.name)}</span><strong>+${money(categoryFact(c.name)+categoryPlan(c.name)-c.amount)}</strong></button>`).join('')}</div>`:'<div class="empty-compact">Все категории в пределах лимитов</div>'],goals:['Цели',`<div class="action-list">${state.goals.map(g=>`<button class="detail-row" data-goal-open="${g.id}"><span>${escapeHtml(g.name)}</span><strong>${money(g.saved)} из ${money(g.target)}</strong></button>`).join('')}</div>`],actions:['Что сделать сейчас',`<div class="action-list">${actionProblems().map((p,i)=>`<button class="detail-row" data-problem="${i}"><span>${p.title}</span><strong>Разобрать</strong></button>`).join('')}</div>`]};const d=details[kind]||details.balance;openModal(d[0],d[1],()=>{document.querySelectorAll('[data-route]').forEach(b=>b.onclick=()=>{closeModal();active=b.dataset.route;render()});document.querySelectorAll('[data-category-detail]').forEach(b=>b.onclick=()=>openCategoryProblem(b.dataset.categoryDetail));document.querySelectorAll('[data-goal-open]').forEach(b=>b.onclick=()=>{closeModal();active='goals';render();setTimeout(()=>openGoalModal(b.dataset.goalOpen),0)});document.querySelectorAll('[data-problem]').forEach(b=>b.onclick=()=>openProblemDetail(+b.dataset.problem))})}
function recommendations(){
 const t=totals(),r=[];
 const unpaid=state.obligations.filter(x=>!isPaid(x));if(unpaid.length)r.push(`Оплатить ${unpaid.length} обязательных платежа на <strong>${money(sum(unpaid,x=>x.amount))}</strong>.`);
 overages().forEach(c=>r.push(`<strong>${escapeHtml(c.name)}</strong>: факт и активный план выше лимита на ${money(categoryFact(c.name)+categoryPlan(c.name)-c.amount)}.`));
 const creditNeed=Math.max(0,(state.creditCard.plannedPayment||state.creditCard.minPayment)-state.creditCard.paidThisMonth);if(creditNeed)r.push(`По кредитке нужно доплатить <strong>${money(creditNeed)}</strong> до ${state.creditCard.dueDay} числа.`);
 if(t.free<0)r.push(`Свободный остаток отрицательный. Можно перенести планы на ${money(Math.abs(t.free))}.`);
 if(!r.length)r.push('План устойчив: обязательства покрыты, критических превышений нет.');
 return r;
}
function actionProblems(){const problems=[],unpaid=state.obligations.filter(x=>!isPaid(x));if(unpaid.length)problems.push({kind:'obligations',title:`Не оплачено: ${unpaid.length}`,reason:`До ближайших сроков нужно зарезервировать ${money(sum(unpaid,x=>x.amount))}.`,items:unpaid.map(x=>`${x.title} · ${money(x.amount)} · до ${x.dueDay} числа`)});overages().forEach(c=>problems.push({kind:'category',category:c.name,title:`Перерасход: ${c.name}`,reason:`Факт и планы превышают лимит на ${money(categoryFact(c.name)+categoryPlan(c.name)-c.amount)}.`,items:categoryOperations(c.name).map(o=>`${niceDate(o.date)} · ${o.subcategory||o.category} · ${money(o.amount)}`)}));const need=Math.max(0,(state.creditCard.plannedPayment||state.creditCard.minPayment)-state.creditCard.paidThisMonth);if(need)problems.push({kind:'credit',title:'Платёж по кредитке',reason:`До ${state.creditCard.dueDay} числа осталось внести ${money(need)}.`,items:[]});if(totals().free<0)problems.push({kind:'budget',title:'Недостаточно свободных средств',reason:`Резервы превышают доступный остаток на ${money(Math.abs(totals().free))}.`,items:state.plans.filter(p=>p.status==='Запланировано').slice(0,5).map(p=>`${p.title} · ${money(p.amount)}`)});if(!problems.length)problems.push({kind:'ok',title:'План под контролем',reason:'Обязательства покрыты, проблемных лимитов нет.',items:[]});return problems}
function openProblemDetail(index){const p=actionProblems()[index];if(!p)return;const actions=p.kind==='category'?`<button class="button gold" id="problemEditCategory">Изменить лимит</button><button class="button secondary" id="problemOperations">Операции категории</button>`:p.kind==='obligations'?`<button class="button gold" id="problemPlan">Открыть обязательства</button>`:p.kind==='credit'?`<button class="button gold" id="problemCredit">Настроить платёж</button>`:p.kind==='budget'?`<button class="button gold" id="problemPlans">Пересмотреть планы</button>`:'';openModal(p.title,`<div class="problem-detail"><div class="insight"><strong>Причина</strong><p>${p.reason}</p></div><div><div class="card-title">Последние операции и объекты</div>${p.items.length?`<div class="detail-list">${p.items.map(x=>`<span>${escapeHtml(x)}</span>`).join('')}</div>`:'<div class="empty-compact">Связанных операций нет</div>'}</div><div class="button-row">${actions}</div></div>`,()=>{const route=id=>{const b=el(id);if(b)b.onclick=()=>{closeModal();active='plan';render()}};route('#problemPlan');route('#problemCredit');route('#problemPlans');const edit=el('#problemEditCategory');if(edit)edit.onclick=()=>openDictionaryModal('categories',p.category,'analytics');const ops=el('#problemOperations');if(ops)ops.onclick=()=>{closeModal();active='entry';opFilters.search=p.category;render()}})}
function openCategoryProblem(name){const problems=actionProblems(),index=problems.findIndex(x=>x.kind==='category'&&x.category===name);if(index>=0)openProblemDetail(index);else openCategorySettings(name)}
function openCategorySettings(name){openDictionaryModal('categories',name,'analytics')}
function assistantActions(){const result=[...recommendations()],repeats=repeatedOverages();repeats.forEach(x=>result.push(`<strong>${escapeHtml(x.name)}</strong>: лимит превышался ${x.months} мес. подряд — пересмотрите лимит или регулярные траты.`));const trend=expenseTrend();if(trend)result.push(`Расходы ${trend.direction==='up'?'выросли':'снизились'} на <strong>${money(Math.abs(trend.delta))}</strong> к прошлому месяцу.`);return result.slice(0,6)}
function repeatedOverages(){const months=[...new Set(state.operations.map(o=>o.date.slice(0,7)))].sort(),out=[];state.categories.filter(c=>c.controlType==='limit').forEach(c=>{let count=0;months.forEach(m=>{const fact=sum(state.operations.filter(o=>o.category===c.name&&o.date.startsWith(m)&&operationKind(o)==='expense'),o=>o.amount);if(fact>c.amount)count++});if(count>=2)out.push({name:c.name,months:count})});return out}
function expenseTrend(){const months=[...new Set(state.operations.map(o=>o.date.slice(0,7)))].sort();if(months.length<2)return null;const values=months.slice(-2).map(m=>sum(state.operations.filter(o=>o.date.startsWith(m)&&['expense','credit'].includes(operationKind(o))),o=>o.amount)),delta=values[1]-values[0];return{delta,direction:delta>=0?'up':'down'}}

function entryScreen(){
 el('#screen').innerHTML=`<div class="stack">${title('Операции','Фактические движения по счетам',`<button class="add-button" id="addOperation" aria-label="Добавить операцию">+</button>`)}
  <div class="page-actions search-only"><div class="search-box"><input id="operationSearch" value="${escapeHtml(opFilters.search)}" placeholder="Поиск по операциям и комментариям"></div></div>
  <section class="card"><div class="filter-row">${['Все',...state.dictionaries.operationTypes,'Вывод из накоплений'].filter((x,i,a)=>a.indexOf(x)===i).map(x=>`<button class="chip ${opFilters.type===x?'active':''}" data-op-type="${escapeHtml(x)}">${escapeHtml(x)}</button>`).join('')}</div><div class="form-grid" style="margin-top:12px"><div class="field"><label>Плановость</label><select id="plannedFilter">${optionList(['Все',...state.dictionaries.plannedValues],opFilters.planned)}</select></div><div class="field"><label>Счёт</label><select id="accountFilter">${optionList(['Все',...state.dictionaries.accounts],opFilters.account)}</select></div><div class="field"><label>Группировка</label><select id="groupFilter"><option value="date" ${opFilters.groupBy==='date'?'selected':''}>По дате</option><option value="category" ${opFilters.groupBy==='category'?'selected':''}>По категории</option><option value="month" ${opFilters.groupBy==='month'?'selected':''}>По месяцу</option></select></div></div></section>
  <div id="operationList" class="stack">${operationGroups()}</div>
 </div>`;
 const open=()=>openOperationModal();el('#addOperation').onclick=open;
 el('#operationSearch').oninput=e=>{opFilters.search=e.target.value;el('#operationList').innerHTML=operationGroups();bindOperationActions()};
 document.querySelectorAll('[data-op-type]').forEach(b=>b.onclick=()=>{opFilters.type=b.dataset.opType;entryScreen()});
 el('#plannedFilter').onchange=e=>{opFilters.planned=e.target.value;entryScreen()};el('#accountFilter').onchange=e=>{opFilters.account=e.target.value;entryScreen()};el('#groupFilter').onchange=e=>{opFilters.groupBy=e.target.value;entryScreen()};
 bindOperationActions();
}
function filteredOperations(){
 const q=opFilters.search.trim().toLowerCase();return [...state.operations].filter(o=>(opFilters.type==='Все'||o.type===opFilters.type)&&(opFilters.planned==='Все'||o.plannedFlag===opFilters.planned)&&(opFilters.account==='Все'||o.account===opFilters.account)&&(!q||[o.category,o.subcategory,o.comment,o.group].join(' ').toLowerCase().includes(q))).sort((a,b)=>b.date.localeCompare(a.date));
}
function operationGroups(){
 const ops=filteredOperations();if(!ops.length)return '<section class="card empty">Операции не найдены</section>';
 const groups={};ops.forEach(o=>{const key=opFilters.groupBy==='category'?o.category:opFilters.groupBy==='month'?o.date.slice(0,7):o.date;(groups[key]??=[]).push(o)});
 return Object.entries(groups).map(([key,items])=>`<section class="card"><div class="card-title">${opFilters.groupBy==='date'?niceDate(key):escapeHtml(key)} <span style="float:right">${money(sum(items,x=>x.amount))}</span></div><div class="list">${items.map(operationItem).join('')}</div></section>`).join('');
}
function operationItem(o){const kind=operationKind(o),positive=['income','withdrawal'].includes(kind);return `<div class="list-item"><div class="list-icon">${kind==='income'?'＋':kind==='expense'?'−':'◇'}</div><div><strong>${escapeHtml(o.subcategory||o.category)}</strong><small>${escapeHtml(o.category)} · ${escapeHtml(o.account)}</small>${o.comment?`<p class="muted">${escapeHtml(o.comment)}</p>`:''}<span class="status ${['Нет','Неплановая'].includes(o.plannedFlag)?'warn':''}">${escapeHtml(o.plannedFlag)}</span><div class="icon-actions"><button data-edit-operation="${o.id}">Изменить</button><button data-delete-operation="${o.id}">Удалить</button></div></div><div class="amount ${positive?'income':'expense'}">${positive?'+':'−'}${money(o.amount)}</div></div>`}
function bindOperationActions(){document.querySelectorAll('[data-edit-operation]').forEach(b=>b.onclick=()=>openOperationModal(b.dataset.editOperation));document.querySelectorAll('[data-delete-operation]').forEach(b=>b.onclick=()=>{if(confirm('Удалить операцию?')){state.operations=state.operations.filter(x=>x.id!==b.dataset.deleteOperation);save();entryScreen();toast('Операция удалена')}})}
function subcategoryOptions(category){return[...new Set([...(state.dictionaries.subcategories?.[category]||[]),...state.operations.filter(o=>o.category===category).map(o=>o.subcategory),...state.plans.filter(p=>p.category===category).map(p=>p.subcategory)].filter(Boolean))].sort((a,b)=>a.localeCompare(b,'ru'))}
function fillSubcategoryList(listId,category){const list=el('#'+listId);if(list)list.innerHTML=subcategoryOptions(category).map(x=>`<option value="${escapeHtml(x)}">`).join('')}
function bindSearchableSelect(searchId,selectId,items,current,onChange){const search=el('#'+searchId),select=el('#'+selectId);const draw=()=>{const q=search.value.trim().toLowerCase(),filtered=items.filter(x=>x.toLowerCase().includes(q)),selected=select.value||current;select.innerHTML=filtered.map(x=>`<option ${x===selected?'selected':''}>${escapeHtml(x)}</option>`).join('');if(!select.value&&filtered.length)select.value=filtered[0];if(onChange)onChange(select.value)};search.oninput=draw;select.onchange=()=>onChange&&onChange(select.value);draw()}
function openOperationModal(id){
 const incomeCategory=state.categories[0]?.name||'',firstCategory=state.categories.find((c,i)=>i>0&&c.controlType!=='goal')?.name||incomeCategory,old=state.operations.find(x=>x.id===id),o=old||{date:todayISO(),type:state.dictionaries.operationTypes[1]||state.dictionaries.operationTypes[0],category:firstCategory,subcategory:'',amount:'',account:state.dictionaries.accounts[0]||'',plannedFlag:state.dictionaries.plannedValues[0]||'',comment:'',group:state.categories.find(c=>c.name===firstCategory)?.group||''};
 const types=[...state.dictionaries.operationTypes,'Вывод из накоплений'].filter((x,i,a)=>a.indexOf(x)===i),cats=state.categories.map(c=>c.name);
 openModal(old?'Редактирование операции':'Новая операция',`<form id="operationForm" class="form-card"><div class="field"><label>Дата</label><input name="date" type="date" value="${o.date}" required></div><div class="field"><label>Тип</label><select name="type">${optionList(types,o.type)}</select></div><div class="field full"><label>Поиск категории</label><input id="opCategorySearch" type="search" placeholder="Начните вводить название"><select id="opCategorySelect" name="category" required style="margin-top:7px"></select></div><div class="field"><label>Подкатегория</label><input name="subcategory" list="opSubcategoryOptions" value="${escapeHtml(o.subcategory)}" placeholder="Выберите или создайте новую"><datalist id="opSubcategoryOptions"></datalist></div><div class="field"><label>Сумма</label><input name="amount" type="number" min="1" value="${o.amount}" required></div><div class="field"><label>Счёт</label><select name="account">${optionList(state.dictionaries.accounts,o.account)}</select></div><div class="field"><label>Плановость</label><select name="plannedFlag">${optionList(state.dictionaries.plannedValues,o.plannedFlag)}</select></div><div class="field"><label>Группа</label><select id="operationGroup" name="group">${optionList(state.dictionaries.groups,o.group)}</select></div><div class="field full"><label>Комментарий</label><textarea name="comment" rows="3">${escapeHtml(o.comment)}</textarea></div><button class="button gold full">${old?'Сохранить':'Добавить'}</button></form>`,()=>{const onCategory=category=>{fillSubcategoryList('opSubcategoryOptions',category);const cat=state.categories.find(c=>c.name===category),group=el('#operationGroup');if(cat&&group&&state.dictionaries.groups.includes(cat.group))group.value=cat.group};bindSearchableSelect('opCategorySearch','opCategorySelect',cats,o.category,onCategory);el('#opCategorySelect').value=o.category;onCategory(o.category);el('#operationForm').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries()),isIncome=v.type===state.dictionaries.operationTypes[0];if(isIncome&&v.category!==incomeCategory){toast('Для дохода выберите категорию «'+incomeCategory+'»');return}if(!isIncome&&v.category===incomeCategory){toast('Категория «'+incomeCategory+'» доступна только для дохода');return}v.amount=+v.amount;v.id=old?.id||'o'+Date.now();v.createdAt=old?.createdAt||new Date().toISOString();if(v.subcategory){state.dictionaries.subcategories[v.category]??=[];if(!state.dictionaries.subcategories[v.category].includes(v.subcategory))state.dictionaries.subcategories[v.category].push(v.subcategory)}if(old)Object.assign(old,v);else state.operations.push(v);save();closeModal();entryScreen();toast(old?'Операция обновлена':'Операция добавлена')}});
}

function planScreen(){
 const cc=state.creditCard,need=Math.max(0,(cc.plannedPayment||cc.minPayment)-cc.paidThisMonth),unpaid=state.obligations.filter(x=>!isPaid(x));
 el('#screen').innerHTML=`<div class="stack">${title('План и обязательства','Планы, платежи и кредитка — без лишних переходов',`<button class="add-button" id="addPlan" aria-label="Добавить план">+</button>`)}
  <section class="card"><div class="card-title">Активные планы</div><div class="list">${state.plans.length?state.plans.map(planItem).join(''):'<div class="empty-compact">Планов пока нет</div>'}</div></section>
  <section class="card"><div class="card-title">Кредитка</div><div class="plan-overview"><div><span>Долг</span><strong>${money(cc.debt)}</strong></div><div><span>Плановый платёж</span><strong>${money(cc.plannedPayment||cc.minPayment)}</strong></div><div><span>Доплатить</span><strong style="color:var(--gold)">${money(need)}</strong></div></div>${progress(cc.paidThisMonth,cc.plannedPayment||cc.minPayment)}<p class="muted">Минимум ${money(cc.minPayment)} · дополнительно ${money(cc.extraPayment||0)} · срок до ${cc.dueDay} числа</p><button class="button secondary" id="editCredit">Настроить кредитку</button></section>
  <section class="card"><div class="card-title">Обязательные платежи</div><div class="action-list">${state.obligations.map(obligationRow).join('')}</div><button class="button secondary" id="addObligation" style="margin-top:12px">+ Добавить обязательство</button></section>
 </div>`;
 el('#addPlan').onclick=()=>openPlanModal();el('#editCredit').onclick=openCreditModal;el('#addObligation').onclick=()=>openObligationModal();
 document.querySelectorAll('[data-edit-plan]').forEach(b=>b.onclick=()=>openPlanModal(b.dataset.editPlan));document.querySelectorAll('[data-delete-plan]').forEach(b=>b.onclick=()=>{if(confirm('Удалить план?')){state.plans=state.plans.filter(x=>x.id!==b.dataset.deletePlan);save();planScreen()}});document.querySelectorAll('[data-plan-status]').forEach(s=>s.onchange=()=>{const p=state.plans.find(x=>x.id===s.dataset.planStatus);if(p){p.status=s.value;save();planScreen()}});document.querySelectorAll('[data-toggle-obligation]').forEach(b=>b.onclick=()=>{const x=state.obligations.find(v=>v.id===b.dataset.toggleObligation);if(x){setPaid(x,!isPaid(x));save();planScreen()}});document.querySelectorAll('[data-edit-obligation]').forEach(b=>b.onclick=()=>openObligationModal(b.dataset.editObligation));
}
function planItem(p){return `<div class="list-item"><div class="list-icon">▣</div><div><strong>${escapeHtml(p.title)}</strong><small>${escapeHtml(p.category)} · ${niceDate(p.date)} · ${p.priority}</small><span class="status ${p.status==='Отменено'?'warn':p.status==='Выполнено'?'good':''}">${p.status}</span><div class="icon-actions"><button data-edit-plan="${p.id}">Изменить</button><button data-delete-plan="${p.id}">Удалить</button></div></div><div><div class="amount">${money(p.amount)}</div><select data-plan-status="${p.id}">${optionList(state.dictionaries.planStatuses,p.status)}</select></div></div>`}
function categoryCard(c){const fact=categoryFact(c.name),plan=categoryPlan(c.name),total=fact+plan,left=c.amount-total;let label={fixed:'Фиксированный платёж',limit:'Лимит',plan:'План'}[c.controlType],warn=c.controlType==='limit'&&left<0;return `<div class="category-card"><div class="category-head"><div><strong>${escapeHtml(c.name)}</strong><div class="category-meta">${label}</div></div><span class="status ${warn?'warn':'good'}">${warn?'Требует разбора':c.controlType==='fixed'?'Фиксированный':'В пределах контроля'}</span></div><div class="category-values"><div>Факт<strong>${money(fact)}</strong></div><div>Активный план<strong>${money(plan)}</strong></div><div>Остаток<strong>${money(left)}</strong></div></div>${progress(total,c.amount)}</div>`}
function obligationRow(x){return `<div class="action-row"><div><strong>${escapeHtml(x.title)}</strong><p>${money(x.amount)} · до ${x.dueDay} числа</p><span class="status ${isPaid(x)?'good':'warn'}">${isPaid(x)?'Оплачено':'Не оплачено'}</span></div><div class="icon-actions"><button data-toggle-obligation="${x.id}">${isPaid(x)?'Вернуть':'Оплачено'}</button><button data-edit-obligation="${x.id}">Изменить</button></div></div>`}
function openPlanModal(id){const old=state.plans.find(x=>x.id===id),incomeCategory=state.categories[0]?.name||'',firstCategory=state.categories.find((c,i)=>i>0&&c.controlType!=='goal')?.name||incomeCategory,p=old||{date:todayISO(),type:state.dictionaries.planTypes[1]||state.dictionaries.operationTypes[1],category:firstCategory,subcategory:'',title:'',amount:'',priority:state.dictionaries.priorities[0],status:state.dictionaries.planStatuses[0],comment:''},types=state.dictionaries.planTypes.length?state.dictionaries.planTypes:state.dictionaries.operationTypes,cats=state.categories.map(c=>c.name);openModal(old?'Редактирование плана':'Новый план',`<form id="planForm" class="form-card"><div class="field"><label>Дата</label><input name="date" type="date" value="${p.date}" required></div><div class="field"><label>Тип</label><select name="type">${optionList(types,p.type)}</select></div><div class="field full"><label>Поиск категории</label><input id="planCategorySearch" type="search" placeholder="Начните вводить название"><select id="planCategorySelect" name="category" required style="margin-top:7px"></select></div><div class="field"><label>Подкатегория</label><input name="subcategory" list="planSubcategoryOptions" value="${escapeHtml(p.subcategory||'')}" placeholder="Выберите или создайте новую"><datalist id="planSubcategoryOptions"></datalist></div><div class="field"><label>Название</label><input name="title" value="${escapeHtml(p.title)}" required></div><div class="field"><label>Сумма</label><input name="amount" type="number" min="1" value="${p.amount}" required></div><div class="field"><label>Приоритет</label><select name="priority">${optionList(state.dictionaries.priorities,p.priority)}</select></div><div class="field"><label>Статус</label><select name="status">${optionList(state.dictionaries.planStatuses,p.status)}</select></div><div class="field full"><label>Комментарий</label><textarea name="comment">${escapeHtml(p.comment)}</textarea></div><button class="button gold full">Сохранить</button></form>`,()=>{const onCategory=category=>fillSubcategoryList('planSubcategoryOptions',category);bindSearchableSelect('planCategorySearch','planCategorySelect',cats,p.category,onCategory);el('#planCategorySelect').value=p.category;onCategory(p.category);el('#planForm').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries()),isIncome=v.type===state.dictionaries.planTypes[0];if(isIncome&&v.category!==incomeCategory){toast('Для дохода выберите категорию «'+incomeCategory+'»');return}if(!isIncome&&v.category===incomeCategory){toast('Категория «'+incomeCategory+'» доступна только для дохода');return}v.amount=+v.amount;v.id=old?.id||'p'+Date.now();v.createdAt=old?.createdAt||new Date().toISOString();if(v.subcategory){state.dictionaries.subcategories[v.category]??=[];if(!state.dictionaries.subcategories[v.category].includes(v.subcategory))state.dictionaries.subcategories[v.category].push(v.subcategory)}if(old)Object.assign(old,v);else state.plans.push(v);save();closeModal();planScreen();toast('План сохранён')}})}
function openCreditModal(){const c=state.creditCard;openModal('Кредитка',`<form id="creditForm" class="form-card"><div class="field"><label>Лимит</label><input name="limit" type="number" value="${c.limit||0}"></div><div class="field"><label>Текущий долг</label><input name="debt" type="number" value="${c.debt}" required></div><div class="field"><label>Минимальный платёж</label><input name="minPayment" type="number" value="${c.minPayment}" required></div><div class="field"><label>Доплата сверху</label><input name="extraPayment" type="number" value="${c.extraPayment||0}"></div><div class="field"><label>Плановый платёж</label><input name="plannedPayment" type="number" value="${c.plannedPayment||c.minPayment}" required></div><div class="field"><label>Оплачено в месяце</label><input name="paidThisMonth" type="number" value="${c.paidThisMonth}" required></div><div class="field"><label>Срок платежа, число</label><input name="dueDay" type="number" min="1" max="31" value="${c.dueDay}" required></div><button class="button gold">Сохранить</button></form>`,()=>{el('#creditForm').onsubmit=e=>{e.preventDefault();Object.entries(Object.fromEntries(new FormData(e.target).entries())).forEach(([k,v])=>c[k]=+v);save();closeModal();planScreen()}})}
function openObligationModal(id){const old=state.obligations.find(x=>x.id===id),x=old||{title:'',amount:'',dueDay:1,status:'unpaid',category:''};openModal(old?'Редактирование обязательства':'Новое обязательство',`<form id="obligationForm" class="form-card"><div class="field"><label>Название</label><input name="title" value="${escapeHtml(x.title)}" required></div><div class="field"><label>Сумма</label><input name="amount" type="number" min="1" value="${x.amount}" required></div><div class="field"><label>Срок, число месяца</label><input name="dueDay" type="number" min="1" max="31" value="${x.dueDay}" required></div><div class="field"><label>Категория</label><select name="category">${optionList(state.categories.map(c=>c.name),x.category)}</select></div><div class="field"><label>Статус</label><select name="status"><option value="unpaid" ${isPaid(x)?'':'selected'}>Не оплачено</option><option value="paid" ${isPaid(x)?'selected':''}>Оплачено</option></select></div><button class="button gold">Сохранить</button></form>`,()=>{el('#obligationForm').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries());v.amount=+v.amount;v.dueDay=+v.dueDay;v.id=old?.id||'b'+Date.now();if(old)Object.assign(old,v);else state.obligations.push(v);save();closeModal();planScreen()}})}

function analyticsScreen(){
 const unplanned=state.operations.filter(o=>operationKind(o)==='expense'&&['Нет','Неплановая'].includes(o.plannedFlag)),months=monthSummary(),expenses=categoryExpenses(),expenseTotal=sum(expenses,x=>x.fact),colors=['#142432','#657586','#7796b2','#bd8128','#a97830','#66756f','#466b78','#9b7050'],segments=expenses.map((x,i)=>({x,color:colors[i%colors.length],pct:expenseTotal?x.fact/expenseTotal*100:0}));let cursor=0;const gradient=segments.map(s=>{const start=cursor;cursor+=s.pct;return `${s.color} ${start}% ${cursor}%`}).join(',');
 el('#screen').innerHTML=`<div class="stack">${title('Аналитика','Только данные, выводы и действия')}
  <section class="card"><div class="card-title">Распределение расходов</div><div class="donut-row"><div class="donut analytics-donut" style="background:conic-gradient(${gradient||'#d5dce2 0 100%'})"><div class="donut-center"><span>Всего<strong>${money(expenseTotal)}</strong></span></div></div><div class="legend">${segments.map(s=>`<button class="legend-item category-link" data-category-settings="${escapeHtml(s.x.name)}"><i class="dot" style="background:${s.color}"></i><span>${escapeHtml(s.x.name)}</span><strong>${Math.round(s.pct)}%</strong></button>`).join('')}</div></div></section>
  <section class="card"><div class="card-title">Факт против плана</div><div class="stack">${state.categories.filter(c=>['limit','plan','fixed'].includes(c.controlType)).map(c=>{const f=categoryFact(c.name),p=c.amount,left=p-f;return `<button class="category-card category-link" data-category-settings="${escapeHtml(c.name)}"><div class="category-head"><strong>${escapeHtml(c.name)}</strong><span class="status ${left<0?'warn':'good'}">${left<0?'Перерасход':'Остаток '+money(left)}</span></div><div class="category-values"><div>Факт<strong>${money(f)}</strong></div><div>План / лимит<strong>${money(p)}</strong></div><div>Активные планы<strong>${money(categoryPlan(c.name))}</strong></div></div>${progress(f,p)}</button>`}).join('')}</div></section>
  <div class="wide-grid"><section class="card"><div class="card-title">Неплановые расходы</div><div class="list">${unplanned.length?unplanned.map(operationItem).join(''):'<div class="empty-compact">Неплановых расходов нет</div>'}</div></section><section class="card"><div class="card-title">Центр действий</div><div class="action-list">${actionProblems().map((p,i)=>`<div class="action-row"><div><strong>${p.title}</strong><p>${p.reason}</p></div><button class="tiny-button" data-problem="${i}">Разобрать</button></div>`).join('')}</div></section></div>
  <section class="card"><div class="card-title">История месяцев</div><div class="year-grid">${months.map(m=>`<div class="year-cell"><span>${m.label}</span><strong>${money(m.income-m.expense)}</strong><small>Доход ${money(m.income)}<br>Расход ${money(m.expense)}</small></div>`).join('')}</div></section>
  <section class="card"><div class="card-title">Годовой обзор</div><div class="plan-overview"><div><span>Доход</span><strong>${money(sum(months,x=>x.income))}</strong></div><div><span>Расход</span><strong>${money(sum(months,x=>x.expense))}</strong></div><div><span>Баланс</span><strong style="color:var(--gold)">${money(sum(months,x=>x.income-x.expense))}</strong></div></div></section>
 </div>`;
 document.querySelectorAll('[data-problem]').forEach(b=>b.onclick=()=>openProblemDetail(+b.dataset.problem));document.querySelectorAll('[data-category-settings]').forEach(b=>b.onclick=()=>openCategorySettings(b.dataset.categorySettings));bindOperationActions();
}
function monthSummary(){const map={};state.operations.forEach(o=>{const k=o.date.slice(0,7),kind=operationKind(o);map[k]??={income:0,expense:0};if(kind==='income')map[k].income+=+o.amount;if(['expense','credit'].includes(kind))map[k].expense+=+o.amount});return Object.entries(map).sort((a,b)=>a[0].localeCompare(b[0])).map(([k,v])=>({...v,key:k,label:new Date(k+'-01T00:00').toLocaleDateString('ru-RU',{month:'short',year:'2-digit'})}))}

function goalsScreen(){
 el('#screen').innerHTML=`<div class="stack">${title('Цели','Несколько целей, темп и история',`<button class="add-button" id="addGoal" aria-label="Добавить цель">+</button>`)}
  ${state.goals.map(goalCard).join('')}
 </div>`;
 el('#addGoal').onclick=()=>openGoalModal();document.querySelectorAll('[data-edit-goal]').forEach(b=>b.onclick=()=>openGoalModal(b.dataset.editGoal));document.querySelectorAll('[data-goal-transaction]').forEach(b=>b.onclick=()=>openGoalTransaction(b.dataset.goalTransaction,b.dataset.kind));document.querySelectorAll('[data-delete-goal]').forEach(b=>b.onclick=()=>{if(confirm('Удалить цель?')){state.goals=state.goals.filter(x=>x.id!==b.dataset.deleteGoal);save();goalsScreen()}});
}
function goalCard(g){const left=Math.max(0,g.target-g.saved),months=Math.ceil(left/Math.max(1,g.monthly)),real=months<=24,forecastDate=addMonths(new Date(),months),deadlineMonths=g.deadline?Math.max(1,Math.ceil((new Date(g.deadline)-new Date())/2629800000)):months,requiredMonthly=Math.ceil(left/deadlineMonths),requiredWeekly=Math.ceil(requiredMonthly/4.345),requiredDaily=Math.ceil(requiredMonthly/30.44),history=state.operations.filter(o=>o.category===g.name&&['savings','withdrawal'].includes(operationKind(o))).slice(-4).reverse(),forecast=Array.from({length:Math.min(6,months||1)},(_,i)=>({date:addMonths(new Date(),i+1),saved:Math.min(g.target,g.saved+g.monthly*(i+1))}));return `<section class="card goal-card"><div class="goal-head"><div><h3>${escapeHtml(g.name)}</h3><span class="status">${escapeHtml(g.type)}</span></div><div class="icon-actions"><button data-edit-goal="${g.id}">Изменить</button><button data-delete-goal="${g.id}">Удалить</button></div></div><div class="goal-balance">${money(g.saved)} <small>из ${money(g.target)}</small></div>${progress(g.saved,g.target)}<div class="summary-grid"><div class="summary-card"><span class="eyebrow">Осталось</span><strong class="value">${money(left)}</strong></div><div class="summary-card ${real?'':'warn'}"><span class="eyebrow">Дата достижения</span><strong class="value compact">${forecastDate.toLocaleDateString('ru-RU',{month:'long',year:'numeric'})}</strong><span class="hint">При взносе ${money(g.monthly)} / мес.</span></div></div><div class="contribution-grid"><span>В месяц<strong>${money(requiredMonthly)}</strong></span><span>В неделю<strong>${money(requiredWeekly)}</strong></span><span>В день<strong>${money(requiredDaily)}</strong></span></div><div><div class="card-title">Прогноз накопления</div><div class="goal-forecast">${forecast.map(x=>`<div><i style="height:${Math.max(8,x.saved/g.target*100)}%"></i><strong>${money(x.saved)}</strong><span>${monthLabel(x.date)}</span></div>`).join('')}</div></div><div class="button-row"><button class="button gold" data-goal-transaction="${g.id}" data-kind="deposit">Пополнить</button><button class="button secondary" data-goal-transaction="${g.id}" data-kind="withdraw">Вывести</button></div><div class="goal-history">${history.length?history.map(o=>`<span>${niceDate(o.date)} · ${operationKind(o)==='savings'?'+':'−'}${money(o.amount)}</span>`).join(''):'<span>История движений пока пуста</span>'}</div></section>`}
function openGoalModal(id){const old=state.goals.find(x=>x.id===id),g=old||{name:'',type:'Покупка',target:'',saved:0,monthly:10000,deadline:''};openModal(old?'Редактирование цели':'Новая цель',`<form id="goalForm" class="form-card"><div class="field"><label>Название</label><input name="name" value="${escapeHtml(g.name)}" required></div><div class="field"><label>Тип</label><select name="type">${optionList(['Подушка','Покупка','Путешествие','Образование','Другое'],g.type)}</select></div><div class="field"><label>Цель</label><input name="target" type="number" min="1" value="${g.target}" required></div><div class="field"><label>Накоплено</label><input name="saved" type="number" min="0" value="${g.saved}" required></div><div class="field"><label>Взнос в месяц</label><input name="monthly" type="number" min="1" value="${g.monthly}" required></div><div class="field"><label>Желаемый срок</label><input name="deadline" type="date" value="${g.deadline||''}"></div><button class="button gold">Сохранить</button></form>`,()=>{el('#goalForm').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries());['target','saved','monthly'].forEach(k=>v[k]=+v[k]);v.id=old?.id||'g'+Date.now();v.createdAt=old?.createdAt||new Date().toISOString();if(old)Object.assign(old,v);else state.goals.push(v);save();closeModal();goalsScreen()}})}
function openGoalTransaction(id,kind){const g=state.goals.find(x=>x.id===id),savingType=state.dictionaries.operationTypes[3]||'Накопления',account=state.dictionaries.accounts.find(x=>x.toLowerCase().includes('накоп'))||state.dictionaries.accounts[0]||'',planned=state.dictionaries.plannedValues[0]||'';openModal(kind==='deposit'?'Пополнение цели':'Вывод из цели',`<form id="goalTransaction" class="form-card"><div class="field"><label>Дата</label><input name="date" type="date" value="${todayISO()}" required></div><div class="field"><label>Сумма</label><input name="amount" type="number" min="1" required></div><div class="field full"><label>Комментарий</label><input name="comment"></div><button class="button gold">Сохранить</button></form>`,()=>{el('#goalTransaction').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries()),amount=+v.amount;if(kind==='withdraw'&&amount>g.saved){toast('Недостаточно средств в цели');return}g.saved+=kind==='deposit'?amount:-amount;state.operations.push({id:'o'+Date.now(),date:v.date,type:kind==='deposit'?savingType:'Вывод из накоплений',category:g.name,subcategory:kind==='deposit'?'Пополнение':'Вывод',amount,account,plannedFlag:planned,comment:v.comment,group:state.categories.find(c=>c.name===g.name)?.group||'',createdAt:new Date().toISOString()});save();closeModal();goalsScreen();toast('Движение сохранено')}})}

function localStorageSection(){return `<section class="card local-storage-account"><div class="card-title">Локальное сохранение</div><p class="muted">Данные автоматически сохраняются в браузере по стабильному ключу <code>${STORAGE_KEY}</code>. При обновлении файлов приложения данные останутся на месте, если ссылка или домен не меняются.</p><div class="sync-panel"><span class="sync-state saved">локальная копия</span><span class="muted">${state.updatedAt?'Обновлено: '+new Date(state.updatedAt).toLocaleString('ru-RU'):'Ещё не сохранялось'}</span></div></section>`}
function settingsScreen(){
 el('#screen').innerHTML=`<div class="stack">${title('Настройки','Справочники, локальное сохранение и резервные копии')}
  ${localStorageSection()}
  <section class="card"><div class="card-title">Доход по умолчанию</div><div class="setting-row"><span>Основная зарплата · ${state.settings.paydayMain} число</span><input id="incomeMain" type="number" value="${state.settings.incomeMain}"></div><div class="setting-row"><span>Вторая часть · ${state.settings.paydaySecond} число</span><input id="incomeSecond" type="number" value="${state.settings.incomeSecond}"></div><button id="saveSettings" class="button gold" style="margin-top:16px">Сохранить</button></section>
  <section class="card"><div class="card-title">Управление справочниками</div>${dictionarySection('Категории','categories',state.categories.map(c=>c.name))}${dictionarySection('Типы операций','operationTypes',state.dictionaries.operationTypes)}${dictionarySection('Счета','accounts',state.dictionaries.accounts)}${dictionarySection('Группы','groups',state.dictionaries.groups)}</section>
  <section class="card"><div class="card-title">Резервные копии</div><div class="button-row"><button id="exportJson" class="button">Экспорт JSON</button><button id="exportCsv" class="button secondary">Экспорт CSV</button><label class="button secondary">Импорт JSON<input id="importJson" type="file" accept="application/json" hidden></label></div></section>
  <section class="card"><div class="card-title">О приложении</div><p class="report">Исходные категории, операции, планы, кредитка и цель импортированы из финансовой модели Excel V10. Лимиты, планы, обязательства и цели рассчитываются независимо.</p><button id="resetData" class="button secondary">Сбросить все данные</button></section>
 </div>`;
 el('#saveSettings').onclick=()=>{state.settings.incomeMain=+el('#incomeMain').value;state.settings.incomeSecond=+el('#incomeSecond').value;save();toast('Настройки сохранены')};el('#exportJson').onclick=exportJson;el('#exportCsv').onclick=exportCsv;el('#importJson').onchange=importJson;el('#resetData').onclick=()=>{if(confirm('Вы точно хотите удалить все сохранённые данные? Это действие нельзя отменить.')){state=migrate(clone(seedDefaults));save();render();toast('Данные сброшены')}};document.querySelectorAll('[data-dict-add]').forEach(b=>b.onclick=()=>openDictionaryModal(b.dataset.dictAdd));document.querySelectorAll('[data-dict-edit]').forEach(b=>b.onclick=()=>openDictionaryModal(b.dataset.dictEdit,b.dataset.value));document.querySelectorAll('[data-dict-delete]').forEach(b=>b.onclick=()=>openDictionaryDelete(b.dataset.dictDelete,b.dataset.value));
}
function dictionarySection(label,kind,items){return `<div class="dictionary-block"><div class="category-head"><strong>${label}</strong><button class="tiny-button" data-dict-add="${kind}">+ Добавить</button></div><div class="dictionary-chips">${items.map(x=>`<span class="dictionary-chip">${escapeHtml(x)}<button aria-label="Изменить" data-dict-edit="${kind}" data-value="${escapeHtml(x)}">✎</button><button aria-label="Удалить" data-dict-delete="${kind}" data-value="${escapeHtml(x)}">×</button></span>`).join('')}</div></div>`}
function renameDictionary(kind,oldName,newName){if(kind==='categories'){state.operations.forEach(x=>{if(x.category===oldName)x.category=newName});state.plans.forEach(x=>{if(x.category===oldName)x.category=newName});state.obligations.forEach(x=>{if(x.category===oldName)x.category=newName;if(x.title===oldName)x.title=newName});state.goals.forEach(x=>{if(x.name===oldName)x.name=newName});const c=state.categories.find(x=>x.name===oldName);if(c)c.name=newName;state.dictionaries.categories=state.categories.map(x=>x.name)}else if(kind==='operationTypes'){state.operations.forEach(x=>{if(x.type===oldName)x.type=newName});state.plans.forEach(x=>{if(x.type===oldName)x.type=newName});const i=state.dictionaries.operationTypes.indexOf(oldName);if(i>=0)state.dictionaries.operationTypes[i]=newName}else if(kind==='accounts'){state.operations.forEach(x=>{if(x.account===oldName)x.account=newName});const i=state.dictionaries.accounts.indexOf(oldName);if(i>=0)state.dictionaries.accounts[i]=newName}else if(kind==='groups'){state.operations.forEach(x=>{if(x.group===oldName)x.group=newName});state.categories.forEach(x=>{if(x.group===oldName)x.group=newName});const i=state.dictionaries.groups.indexOf(oldName);if(i>=0)state.dictionaries.groups[i]=newName}}
function transferReferences(kind,oldName,newName){if(kind==='categories'){state.operations.forEach(x=>{if(x.category===oldName)x.category=newName});state.plans.forEach(x=>{if(x.category===oldName)x.category=newName});state.obligations.forEach(x=>{if(x.category===oldName)x.category=newName});state.goals.forEach(x=>{if(x.name===oldName)x.name=newName})}else if(kind==='operationTypes'){state.operations.forEach(x=>{if(x.type===oldName)x.type=newName});state.plans.forEach(x=>{if(x.type===oldName)x.type=newName})}else if(kind==='accounts'){state.operations.forEach(x=>{if(x.account===oldName)x.account=newName})}else if(kind==='groups'){state.operations.forEach(x=>{if(x.group===oldName)x.group=newName});state.categories.forEach(x=>{if(x.group===oldName)x.group=newName})}}
function openDictionaryModal(kind,oldName='',returnTo='settings'){const category=kind==='categories'?state.categories.find(x=>x.name===oldName):null,label={categories:'категорию',operationTypes:'тип операции',accounts:'счёт',groups:'группу'}[kind];openModal(oldName?'Изменить '+label:'Добавить '+label,`<form id="dictionaryForm" class="form-card"><div class="field full"><label>Название</label><input name="name" value="${escapeHtml(oldName)}" required></div>${kind==='categories'?`<div class="field"><label>Группа</label><select name="group">${optionList(state.dictionaries.groups,category?.group||state.dictionaries.groups[0])}</select></div><div class="field"><label>Тип контроля</label><select name="controlType">${optionList(['fixed','limit','plan','goal','none'],category?.controlType||'limit')}</select></div><div class="field"><label>Лимит / план</label><input name="amount" type="number" min="0" value="${category?.amount||0}"></div><div class="field full"><label>Комментарий</label><input name="comment" value="${escapeHtml(category?.comment||'')}"></div>`:''}<button class="button gold full">Сохранить</button></form>`,()=>{el('#dictionaryForm').onsubmit=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target).entries()),name=v.name.trim();if(!name)return;if(oldName&&oldName!==name)renameDictionary(kind,oldName,name);if(!oldName){if(kind==='categories'){state.categories.push({id:'c'+Date.now(),name,group:v.group,controlType:v.controlType,amount:+v.amount||0,comment:v.comment,color:'#7796b2',active:true});state.dictionaries.categories=state.categories.map(x=>x.name)}else if(!state.dictionaries[kind].includes(name))state.dictionaries[kind].push(name)}if(kind==='categories'){const c=state.categories.find(x=>x.name===name);Object.assign(c,{group:v.group,controlType:v.controlType,amount:+v.amount||0,comment:v.comment})}save();closeModal();if(returnTo==='analytics'){active='analytics';analyticsScreen()}else settingsScreen();toast('Справочник обновлён')}})}
function openDictionaryDelete(kind,value){const items=kind==='categories'?state.categories.map(x=>x.name):state.dictionaries[kind],choices=items.filter(x=>x!==value);if(!choices.length){toast('Нельзя удалить последний элемент');return}openModal('Удаление из справочника',`<form id="dictionaryDeleteForm" class="form-card"><p class="report">Куда перенести связанные операции и планы из «${escapeHtml(value)}»?</p><div class="field"><label>Перенести в</label><select name="replacement">${optionList(choices,choices[0])}</select></div><button class="button gold">Перенести и удалить</button></form>`,()=>{el('#dictionaryDeleteForm').onsubmit=e=>{e.preventDefault();const replacement=new FormData(e.target).get('replacement');transferReferences(kind,value,replacement);if(kind==='categories'){state.categories=state.categories.filter(x=>x.name!==value);state.dictionaries.categories=state.categories.map(x=>x.name)}else state.dictionaries[kind]=state.dictionaries[kind].filter(x=>x!==value);save();closeModal();settingsScreen();toast('Элемент удалён, данные перенесены')}})}
function openGlobalSearch(){openModal('Глобальный поиск',`<div class="search-box"><input id="globalSearch" placeholder="Операции, планы и цели"></div><div id="globalResults" class="list" style="margin-top:15px"><div class="empty-compact">Начните вводить запрос</div></div>`,()=>{el('#globalSearch').oninput=e=>{const q=e.target.value.trim().toLowerCase(),items=[];if(q){state.operations.filter(o=>[o.category,o.subcategory,o.comment,o.group].join(' ').toLowerCase().includes(q)).slice(0,8).forEach(o=>items.push(searchResult('operation',o.id,'↔',o.subcategory||o.category,'Операция · '+niceDate(o.date),money(o.amount))));state.plans.filter(p=>[p.title,p.category,p.comment].join(' ').toLowerCase().includes(q)).slice(0,6).forEach(p=>items.push(searchResult('plan',p.id,'▣',p.title,'План · '+niceDate(p.date),money(p.amount))));state.goals.filter(g=>g.name.toLowerCase().includes(q)).forEach(g=>items.push(searchResult('goal',g.id,'◇',g.name,'Цель',money(g.saved))))}el('#globalResults').innerHTML=items.join('')||'<div class="empty-compact">Ничего не найдено</div>';document.querySelectorAll('[data-search-kind]').forEach(b=>b.onclick=()=>openSearchResult(b.dataset.searchKind,b.dataset.searchId))}})}
function searchResult(kind,id,icon,name,meta,amount){return `<button class="list-item search-result" data-search-kind="${kind}" data-search-id="${id}"><span class="list-icon">${icon}</span><span><strong>${escapeHtml(name)}</strong><small>${escapeHtml(meta)}</small></span><span class="amount">${amount}</span></button>`}
function openSearchResult(kind,id){closeModal();active=kind==='operation'?'entry':kind==='plan'?'plan':'goals';render();setTimeout(()=>{if(kind==='operation')openOperationModal(id);if(kind==='plan')openPlanModal(id);if(kind==='goal')openGoalModal(id)},0)}
function notificationItems(){const items=[];state.obligations.filter(x=>!isPaid(x)).forEach(x=>items.push({id:'obligation-'+x.id,text:`${x.title}: оплатить ${money(x.amount)} до ${x.dueDay} числа`,target:'plan'}));overages().forEach(x=>items.push({id:'limit-'+x.id,text:`${x.name}: факт и планы выше лимита`,target:'analytics'}));const need=Math.max(0,(state.creditCard.plannedPayment||state.creditCard.minPayment)-state.creditCard.paidThisMonth);if(need)items.push({id:'credit-payment',text:`Кредитка: доплатить ${money(need)}`,target:'plan'});const prefs=state.settings.notificationPrefs,now=Date.now();return items.filter(x=>!prefs.disabled.includes(x.id)&&(!prefs.snoozed[x.id]||new Date(prefs.snoozed[x.id]).getTime()<=now))}
function openNotifications(){const items=notificationItems();openModal('Уведомления',items.length?`<div class="action-list">${items.map(x=>`<div class="notification-row"><strong>${escapeHtml(x.text)}</strong><div class="icon-actions"><button data-notification-action="open" data-id="${x.id}" data-target="${x.target}">Открыть</button><button data-notification-action="later" data-id="${x.id}">Напомнить позже</button><button data-notification-action="disable" data-id="${x.id}">Больше не напоминать</button></div></div>`).join('')}</div>`:'<div class="empty-compact">Новых уведомлений нет</div>',()=>{document.querySelectorAll('[data-notification-action]').forEach(b=>b.onclick=()=>handleNotification(b.dataset.notificationAction,b.dataset.id,b.dataset.target))})}
function handleNotification(action,id,target){const prefs=state.settings.notificationPrefs;if(action==='open'){closeModal();active=target||'home';render();return}if(action==='later')prefs.snoozed[id]=new Date(Date.now()+86400000).toISOString();if(action==='disable'&&!prefs.disabled.includes(id))prefs.disabled.push(id);save();openNotifications();toast(action==='later'?'Напомним завтра':'Уведомление отключено')}
function openModal(titleText,content,onReady){el('#modalRoot').innerHTML=`<div class="modal-backdrop" role="dialog" aria-modal="true"><div class="modal"><div class="modal-head"><h2>${titleText}</h2><button class="modal-close" aria-label="Закрыть">×</button></div>${content}</div></div>`;document.body.classList.add('modal-open');el('.modal-close').onclick=closeModal;el('.modal-backdrop').onclick=e=>{if(e.target===el('.modal-backdrop'))closeModal()};if(onReady)onReady()}
function closeModal(){el('#modalRoot').innerHTML='';document.body.classList.remove('modal-open')}
function download(name,data,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([data],{type}));a.download=name;a.click();URL.revokeObjectURL(a.href)}
function exportJson(){download(`finance_backup_${todayISO()}.json`,JSON.stringify(migrate(state),null,2),'application/json')}
function exportCsv(){const h=['date','type','category','subcategory','amount','account','plannedFlag','comment','group'],q=v=>'"'+String(v??'').replaceAll('"','""')+'"';download('kontur-operations.csv','\ufeff'+h.join(';')+'\n'+state.operations.map(o=>h.map(k=>q(o[k])).join(';')).join('\n'),'text/csv')}
function validateImportData(data){return data&&typeof data==='object'&&(Array.isArray(data.operations)||Array.isArray(data.incomes)||Array.isArray(data.expenses)||Array.isArray(data.categories)||Array.isArray(data.goals)||data.settings)}
function importJson(e){const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=()=>{try{const parsed=JSON.parse(r.result);if(!validateImportData(parsed)){toast('Файл не похож на резервную копию приложения');return}if(!confirm('Текущие сохранённые данные будут заменены данными из файла. Продолжить?'))return;state=migrate(parsed);save();render();toast('Данные импортированы')}catch{toast('Не удалось прочитать файл')}finally{e.target.value=''}};r.readAsText(f)}
function toast(s){const t=el('#toast');t.textContent=s;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2600)}

el('#globalSearchButton').onclick=openGlobalSearch;
el('#notificationsButton').onclick=openNotifications;
render();
setLocalSaveStatus('saved');
